function findStartSku() {
  let maxNum = 0;
  const filesToCheck = ["data/products.json", "data/products-placeholder.json", "data/products-placeholder-batch2.json"];
  for (const f of filesToCheck) {
    if (!existsSync(f)) continue;
    const d = JSON.parse(readFileSync(f, "utf8"));
    for (const v of Object.values(d)) {
      const s = v.sku || "";
      if (/^p\d+$/.test(s)) {
        const n = parseInt(s.slice(1), 10);
        if (n > maxNum) maxNum = n;
      }
    }
  }
  return maxNum + 1;
}

function toTitle(fname) {
  const base = fname.replace(/\.png$/i, "");
  const upperWords = new Set(["4k","8k","tv","usb","hdmi","led","oled","qled","dvd","gps","ai","vr","ar","nfc","sd","cpu","gpu","ram","ssd","hdd","psu","ups","rgb","fpv","dj","pa","uv","uvb"]);
  return base.split("_").map(w => upperWords.has(w.toLowerCase()) ? w.toUpperCase() : (w.charAt(0).toUpperCase() + w.slice(1))).join(" ");
}

const CREATED_AT = 1782984093000;
const START_SKU = findStartSku();
console.log("Starting SKU number:", START_SKU);

const products = {};
let counter = START_SKU;

for (const [folder, files] of Object.entries(CATEGORY_FILES)) {
  const slug = FOLDER_TO_SLUG[folder];
  for (const fname of files) {
    const title = toTitle(fname);
    const sku = `p${counter}`;
    products[sku] = {
      sellerId: "admin",
      title: title,
      description: `${title} — product details to be completed by admin (image, description, and price pending).`,
      price: 100,
      stock: 10,
      categoryId: slug,
      netWeight: "",
      status: "pending",
      createdAt: CREATED_AT,
      updatedAt: CREATED_AT,
      images: { main: `assets/images/categories/${folder}/${fname}` },
      sku: sku
    };
    counter++;
  }
}

writeFileSync("data/products-placeholder-batch3.json", JSON.stringify(products, null, 2), "utf8");
console.log(`Generated ${Object.keys(products).length} products.`);
console.log(`SKU range: p${START_SKU} to p${counter - 1}`);
